class QueryValidator {
  private val blockedKeywords = Set(
    "DROP", "DELETE", "TRUNCATE", "INSERT", "UPDATE", 
    "CREATE", "ALTER", "GRANT", "REVOKE", "MERGE"
  )
  
  private val allowedCommands = Set("SELECT", "WITH", "SHOW", "DESCRIBE", "EXPLAIN")
  
  def validate(query: String): Either[String, String] = {
    val normalizedQuery = query.trim.toUpperCase
    
    if (normalizedQuery.isEmpty) {
      return Left("Query cannot be empty")
    }
    
    val firstWord = normalizedQuery.split("\\s+")(0)
    if (!allowedCommands.contains(firstWord)) {
      return Left(s"Query must start with one of: ${allowedCommands.mkString(", ")}")
    }
    
    blockedKeywords.foreach { keyword =>
      val pattern = s"\\b$keyword\\b".r
      if (pattern.findFirstIn(normalizedQuery).isDefined) {
        return Left(s"Blocked keyword detected: $keyword")
      }
    }
    
    if (normalizedQuery.contains(";") && normalizedQuery.count(_ == ';') > 1) {
      return Left("Multiple statements not allowed")
    }
    
    if (query.length > 50000) {
      return Left("Query exceeds maximum length of 50000 characters")
    }
    
    Right(query.trim.replaceAll(";+$", ""))
  }
}

class QueryExecutor(spark: SparkSession) {
  import spark.implicits._
  
  private val validator = new QueryValidator()
  private val maxDefaultRows = 10000
  private val defaultTimeoutSeconds = 300
  
  def executeQuery(request: QueryRequest): QueryResult = {
    val startTime = System.currentTimeMillis()
    
    validator.validate(request.sqlQuery) match {
      case Left(error) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          error = Some(s"Validation failed: $error"),
          executionTimeMs = System.currentTimeMillis() - startTime
        )
      
      case Right(validatedQuery) =>
        executeValidatedQuery(request, validatedQuery, startTime)
    }
  }
  
  private def executeValidatedQuery(
    request: QueryRequest, 
    query: String, 
    startTime: Long
  ): QueryResult = {
    val maxRows = request.maxRows.getOrElse(maxDefaultRows).min(maxDefaultRows)
    val timeout = request.timeoutSeconds.getOrElse(defaultTimeoutSeconds)
    
    Try {
      spark.sparkContext.setLocalProperty("spark.scheduler.pool", "queries")
      spark.sparkContext.setJobDescription(s"QueryID: ${request.queryId}, User: ${request.userId}")
      
      val df = spark.sql(query)
      val limitedDf = df.limit(maxRows)
      
      val future = scala.concurrent.Future {
        limitedDf.collect()
      }(scala.concurrent.ExecutionContext.global)
      
      val result = scala.concurrent.Await.result(
        future, 
        scala.concurrent.duration.Duration(timeout, TimeUnit.SECONDS)
      )
      
      val data = result.map { row =>
        row.schema.fieldNames.map { fieldName =>
          val value = Option(row.getAs[Any](fieldName)).getOrElse(null)
          fieldName -> convertValue(value)
        }.toMap
      }.toSeq
      
      QueryResult(
        queryId = request.queryId,
        success = true,
        data = Some(data),
        rowCount = Some(data.length),
        executionTimeMs = System.currentTimeMillis() - startTime
      )
      
    } match {
      case Success(result) => result
      case Failure(ex: scala.concurrent.TimeoutException) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          error = Some(s"Query exceeded timeout of $timeout seconds"),
          executionTimeMs = System.currentTimeMillis() - startTime
        )
      case Failure(ex: ParseException) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          error = Some(s"SQL parsing error: ${ex.getMessage}"),
          executionTimeMs = System.currentTimeMillis() - startTime
        )
      case Failure(ex) =>
        QueryResult(
          queryId = request.queryId,
          success = false,
          error = Some(s"Execution error: ${ex.getMessage}"),
          executionTimeMs = System.currentTimeMillis() - startTime
        )
    }
  }
  
  private def convertValue(value: Any): Any = value match {
    case null => null
    case ts: Timestamp => ts.toString
    case date: java.sql.Date => date.toString
    case bd: java.math.BigDecimal => bd.doubleValue()
    case arr: scala.collection.mutable.WrappedArray[_] => arr.toSeq
    case seq: Seq[_] => seq
    case map: Map[_, _] => map
    case other => other.toString
  }
}

class QueryAuditLogger(spark: SparkSession) {
  import spark.implicits._
  
  private val auditPath = "/data/audit/query_logs"
  
  def logQuery(request: QueryRequest, result: QueryResult): Unit = {
    Try {
      val auditRecord = Seq(AuditRecord(
        queryId = request.queryId,
        userId = request.userId,
        sqlQuery = request.sqlQuery,
        success = result.success,
        rowCount = result.rowCount.getOrElse(0),
        executionTimeMs = result.executionTimeMs,
        error = result.error,
        timestamp = result.timestamp
      ))
      
      spark.createDataset(auditRecord)
        .write
        .mode("append")
        .partitionBy("timestamp")
        .parquet(auditPath)
    }
  }
}

case class AuditRecord(
  queryId: String,
  userId: String,
  sqlQuery: String,
  success: Boolean,
  rowCount: Int,
  executionTimeMs: Long,
  error: Option[String],
  timestamp: Timestamp
)

class DataLakeQueryService(spark: SparkSession) {
  private val executor = new QueryExecutor(spark)
  private val auditLogger = new QueryAuditLogger(spark)
  
  def registerDataSources(): Unit = {
    spark.sql(
      """
        |CREATE DATABASE IF NOT EXISTS analytics
      """.stripMargin)
    
    registerTable("sales_data", "/data/lake/sales")
    registerTable("customer_data", "/data/lake/customers")
    registerTable("product_data", "/data/lake/products")
    registerTable("user_events", "/data/lake/events")
  }
  
  private def registerTable(tableName: String, path: String): Unit = {
    Try {
      spark.sql(
        s"""
           |CREATE TABLE IF NOT EXISTS analytics.$tableName
           |USING parquet
           |LOCATION '$path'
         """.stripMargin)
    }
  }
  
  def processQuery(request: QueryRequest): QueryResult = {
    val result = executor.executeQuery(request)
    auditLogger.logQuery(request, result)
    result
  }
  
  def executeQueryFromAPI(
    queryId: String,
    userId: String,
    sqlQuery: String,
    maxRows: Option[Int] = None,
    timeoutSeconds: Option[Int] = None
  ): QueryResult = {
    val request = QueryRequest(
      queryId = queryId,
      userId = userId,
      sqlQuery = sqlQuery,
      maxRows = maxRows,
      timeoutSeconds = timeoutSeconds
    )
    processQuery(request)
  }
}

object DataAnalyticsPlatform {
  def createSparkSession(): SparkSession = {
    SparkSession.builder()
      .appName("DataLake Query Service")
      .config("spark.sql.adaptive.enabled", "true")
      .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
      .config("spark.sql.broadcastTimeout", "600")
      .config("spark.scheduler.mode", "FAIR")
      .config("spark.sql.sources.partitionOverwriteMode", "dynamic")
      .getOrCreate()
  }
  
  def main(args: Array[String]): Unit = {
    val spark = createSparkSession()
    val queryService = new DataLakeQueryService(spark)
    
    queryService.registerDataSources()
    
    val sampleQuery = """
      SELECT 
        customer_id,
        COUNT(*) as order_count,
        SUM(total_amount) as total_revenue
      FROM analytics.sales_data
      WHERE order_date >= '2024-01-01'
      GROUP BY customer_id
      ORDER BY total_revenue DESC
    """
    
    val result = queryService.executeQueryFromAPI(
      queryId = java.util.UUID.randomUUID().toString,
      userId = "user123",
      sqlQuery = sampleQuery,
      maxRows = Some(100),
      timeoutSeconds = Some(60)
    )
    
    if (result.success) {
      println(s"Query executed successfully in ${result.executionTimeMs}ms")
      println(s"Returned ${result.rowCount.getOrElse(0)} rows")
